import type { Brief, Session, TurnIntent, TurnScore } from "@/lib/types";

type HonestIntentType = "honest_reason" | "honest_question" | "honest_partial";

const HONEST_INTENTS: HonestIntentType[] = [
  "honest_reason",
  "honest_question",
  "honest_partial",
];

const WRONG_INTENTS: Array<TurnIntent["type"]> = [
  "express_misc",
  "defend_misc",
  "probe_minor",
  "probe_trap",
];

type IntentType = TurnIntent["type"];

function avgRubric(scores: TurnScore["scores"]): number {
  return (
    scores.framing +
    scores.questions +
    scores.reasoning +
    scores.uncertainty +
    scores.calibration
  ) / 5;
}

function computeChallengeRate(session: Session): number {
  const recent = session.scores.slice(-5);
  if (recent.length === 0) {
    return 0.5;
  }

  const challenges = recent.filter(
    (score) =>
      /probe|correct|challenge|question|push|catch/i.test(score.tag) ||
      (score.scores.questions >= 3.5 && score.scores.reasoning >= 3),
  ).length;

  return challenges / recent.length;
}

function turnsSinceLastOfType(session: Session, types: IntentType[]): number {
  for (let i = session.turnIntents.length - 1; i >= 0; i -= 1) {
    if (types.includes(session.turnIntents[i].type)) {
      return session.turnIntents.length - 1 - i;
    }
  }
  return Number.POSITIVE_INFINITY;
}

function weightedRandom(
  weights: Record<IntentType, number>,
  random: () => number,
): IntentType {
  const entries = Object.entries(weights).filter(([, weight]) => weight > 0) as Array<
    [IntentType, number]
  >;
  if (entries.length === 0) {
    return "honest_reason";
  }

  const total = entries.reduce((sum, [, weight]) => sum + weight, 0);
  let pick = random() * total;
  for (const [intentType, weight] of entries) {
    pick -= weight;
    if (pick <= 0) {
      return intentType;
    }
  }
  return entries[entries.length - 1][0];
}

function pickHonest(session: Session, random: () => number): TurnIntent {
  const lastIntentType = session.turnIntents.at(-1)?.type;
  const allowed = HONEST_INTENTS.filter((type) => type !== lastIntentType);
  const selected: HonestIntentType =
    allowed[Math.floor(random() * allowed.length)] ?? "honest_reason";
  return { type: selected };
}

function parseKeywords(text: string): string[] {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .filter((word) => word.length >= 4);
}

export function isSurfaceRelevant(misconceptionSurfaceWhen: string, session: Session): boolean {
  const recentUserText = session.turns
    .slice(-2)
    .filter((turn) => turn.role === "user")
    .map((turn) => turn.content.toLowerCase())
    .join(" ");
  if (!recentUserText) {
    return false;
  }

  const keywords = parseKeywords(misconceptionSurfaceWhen);
  return keywords.some((keyword) => recentUserText.includes(keyword));
}

function findMostRecentMiscIntent(session: Session): TurnIntent | null {
  for (let i = session.turnIntents.length - 1; i >= 0; i -= 1) {
    const intent = session.turnIntents[i];
    if (intent.type === "express_misc" || intent.type === "defend_misc") {
      return intent;
    }
  }
  return null;
}

function nextUnusedProbeId(session: Session, brief: Brief): string | null {
  const available = brief.probe_claims.find(
    (probe) => !session.consumedProbes.includes(probe.id),
  );
  return available?.id ?? null;
}

function nextUnusedTrapId(session: Session, brief: Brief): string | null {
  const available = brief.trap_claims.find((trap) => !session.consumedProbes.includes(trap.id));
  return available?.id ?? null;
}

function resolveIntent(
  intentType: IntentType,
  session: Session,
  eligibleMiscs: string[],
  random: () => number,
): TurnIntent {
  switch (intentType) {
    case "honest_reason":
    case "honest_question":
    case "honest_partial":
      return { type: intentType };
    case "express_misc": {
      if (eligibleMiscs.length === 0) {
        return { type: "honest_reason" };
      }
      const miscId = eligibleMiscs[Math.floor(random() * eligibleMiscs.length)];
      return { type: "express_misc", misc_id: miscId };
    }
    case "defend_misc": {
      const latestMisc = findMostRecentMiscIntent(session);
      if (latestMisc?.type === "express_misc" || latestMisc?.type === "defend_misc") {
        return { type: "defend_misc", misc_id: latestMisc.misc_id };
      }
      if (eligibleMiscs.length === 0) {
        return { type: "honest_partial" };
      }
      const miscId = eligibleMiscs[Math.floor(random() * eligibleMiscs.length)];
      return { type: "defend_misc", misc_id: miscId };
    }
    case "probe_minor": {
      const probeId = nextUnusedProbeId(session, session.brief);
      if (!probeId) {
        return { type: "honest_reason" };
      }
      return { type: "probe_minor", probe_id: probeId };
    }
    case "probe_trap": {
      const trapId = nextUnusedTrapId(session, session.brief);
      if (!trapId) {
        return { type: "honest_reason" };
      }
      return { type: "probe_trap", trap_id: trapId };
    }
    case "transfer_check": {
      const updating = Object.entries(session.miscStates)
        .filter(([, state]) => state === "updating")
        .map(([id]) => id);
      if (updating.length === 0) {
        return { type: "honest_reason" };
      }
      return { type: "transfer_check", misc_id: updating[Math.floor(random() * updating.length)] };
    }
  }
}

export function pickIntent(session: Session, random: () => number = Math.random): TurnIntent {
  if (session.turnIntents.length === 0) {
    return { type: "honest_reason" };
  }
  if (session.turnIntents.length === 1) {
    return { type: "honest_question" };
  }

  const lastIntents = session.turnIntents.slice(-5);
  const lastIntent = lastIntents[lastIntents.length - 1];
  const recentScores = session.scores.slice(-3);

  if (lastIntent?.type === "defend_misc") {
    const lastUserScore = recentScores[recentScores.length - 1];
    const userPushedWell = lastUserScore ? avgRubric(lastUserScore.scores) >= 3.5 : false;
    if (!userPushedWell) {
      return { type: "honest_partial" };
    }
    return pickHonest(session, random);
  }

  const wrongInLast5 = lastIntents.filter((intent) => WRONG_INTENTS.includes(intent.type)).length;
  if (wrongInLast5 >= 3) {
    return pickHonest(session, random);
  }

  const turnsSinceProbe = turnsSinceLastOfType(session, ["probe_minor", "probe_trap"]);
  const probesAllowed = turnsSinceProbe >= 5;
  const updatingMisc = Object.entries(session.miscStates).some(([, state]) => state === "updating");

  const weights: Record<IntentType, number> = {
    honest_reason: 30,
    honest_question: 15,
    honest_partial: 15,
    express_misc: 20,
    defend_misc: 6,
    probe_minor: probesAllowed ? 10 : 0,
    probe_trap: probesAllowed ? 4 : 0,
    transfer_check: updatingMisc ? 8 : 0,
  };

  const userChallengeRate = computeChallengeRate(session);
  if (userChallengeRate < 0.3) {
    weights.probe_trap *= 2.5;
    weights.probe_minor *= 1.5;
  }
  if (userChallengeRate > 0.75) {
    weights.honest_reason *= 2;
    weights.express_misc = 0;
    weights.probe_minor = 0;
    weights.probe_trap = 0;
  }

  if (lastIntent) {
    weights[lastIntent.type] = 0;
  }

  const eligibleMiscs = session.brief.misconceptions
    .filter(
      (misconception) =>
        isSurfaceRelevant(misconception.surface_when, session) &&
        session.miscStates[misconception.id] !== "settled",
    )
    .map((misconception) => misconception.id);
  if (eligibleMiscs.length === 0) {
    weights.express_misc = 0;
    weights.defend_misc = 0;
  }

  const probeIds = new Set(session.brief.probe_claims.map((claim) => claim.id));
  const consumedProbeCount = session.consumedProbes.filter((id) => probeIds.has(id)).length;
  if (consumedProbeCount >= session.brief.probe_claims.length) {
    weights.probe_minor = 0;
  }
  const trapIds = new Set(session.brief.trap_claims.map((claim) => claim.id));
  const consumedTrapCount = session.consumedProbes.filter((id) => trapIds.has(id)).length;
  if (consumedTrapCount >= session.brief.trap_claims.length) {
    weights.probe_trap = 0;
  }

  const intentType = weightedRandom(weights, random);
  return resolveIntent(intentType, session, eligibleMiscs, random);
}
